            "userData": "#cloud-config\nautoinstall:\n    version: 1\n    early-commands:\n        - |\n          TARGET_DISK=\"\"\n          CANDIDATES=\"\"\n          for disk in /dev/sd* /dev/nvme*; do\n            if [ -b \"$disk\" ]; then\n              # NO removable devices\n              if [ -f \"/sys/block/${disk##*/}/removable\" ] && [ \"$(cat /sys/block/${disk##*/}/removable)\" = \"1\" ]; then\n                continue\n              fi\n              DISK_SIZE_BYTES=$(blockdev --getsize64 \"$disk\")\n              DISK_SIZE_GB=$((DISK_SIZE_BYTES / 1024 / 1024 / 1024))\n              if [ \"$DISK_SIZE_GB\" -gt 100 ]; then\n                CANDIDATES=\"${CANDIDATES}${CANDIDATES:+ }$disk:$DISK_SIZE_GB\"\n              fi\n            fi\n          done\n\n          # Select the smallest\n          if [ -n \"$CANDIDATES\" ]; then\n            TARGET_DISK=$(echo \"$CANDIDATES\" | tr ' ' '\\n' | sort -t: -k2,2n | head -n1 | cut -d: -f1)\n          else\n            # If that didnt work, pick any non-removable disk randomly\n            ALL_DISKS=\"\"\n            for disk in /dev/sd* /dev/nvme*; do\n              if [ -b \"$disk\" ]; then\n                if [ -f \"/sys/block/${disk##*/}/removable\" ] && [ \"$(cat /sys/block/${disk##*/}/removable)\" = \"1\" ]; then\n                  continue\n                fi\n                ALL_DISKS=\"${ALL_DISKS}${ALL_DISKS:+ }$disk\"\n              fi\n            done\n\n            if [ -z \"$ALL_DISKS\" ]; then\n              # Awww nuts!\n              echo \"No suitable disk found for installation.\" >&2\n              exit 1\n            fi\n\n            TARGET_DISK=$(echo \"$ALL_DISKS\" | tr ' ' '\\n' | shuf -n1)\n            echo \"Warning: No disk >100GB found. Selecting disk randomly: $TARGET_DISK\"\n          fi\n\n          # Replace placeholder in storage config\n          sed -i \"s|path: /dev/target_disk_placeholder|path: ${TARGET_DISK}|\" /autoinstall.yaml\n    storage:\n        layout:\n            name: lvm\n            match:\n                path: /dev/target_disk_placeholder\n    identity:\n        hostname: nvcf-dgxc-k8s-forge-ytl-prd1-w-2733\n        username: dgxc-admin\n        password: $6$jCfWFbdxh1lK09sY$pxFnrW/yXewYFmgoaywu3WKhdPQg0e8DR8jvedAV.udXM0.i5M6wr4Up2S7ZCN9kNDmg.s7fmrOaXE6nEyzPb/ # Welcome123\n    packages:\n        - chrony\n    ntp:\n        enabled: true\n        ntp_client: chrony\n        servers:\n            - 129.6.15.32\n    keyboard:\n        layout: us\n        toggle: null\n        variant: \"\"\n    locale: en_US\n    ssh:\n        allow-pw: true\n        authorized-keys: []\n        install-server: true\n    late-commands:\n        - curtin in-target --target=/target -- sed -i 's|^GRUB_CMDLINE_LINUX=.*|GRUB_CMDLINE_LINUX=\"ipv6.disable=1 console=ttyS1,115200\"|' /etc/default/grub\n        - curtin in-target --target=/target -- update-grub\n    user-data:\n        write_files:\n            - path: /etc/sysctl.d/60-custom.conf\n              owner: root:root\n              permissions: '0755'\n              content: |\n                net.ipv6.conf.all.disable_ipv6 = 1\n                net.ipv6.conf.default.disable_ipv6 = 1\n                net.ipv6.conf.lo.disable_ipv6 = 1\n        runcmd:\n            - [sh, -c, \"lvextend -l +100%FREE /dev/ubuntu-vg/ubuntu-lv\"]\n            - [sh, -c, \"resize2fs /dev/mapper/ubuntu-vg-ubuntu-lv\"]\n            - [sh, -c, \"mkdir -m 755 /etc/apt/keyrings\"]\n            - [sh, -c, \"mkdir -p /etc/dgx/attestation\"]\n            - [sh, -c, \"echo \\\"SERVER=REPLACED-BY-SWE\\\" >> /etc/dgx/attestation/vars\"]\n            - [sh, -c, \"echo \\\"SAN_IP=$(hostname -I | cut -d' ' -f1)\\\" >> /etc/dgx/attestation/vars\"]\n            - [sh, -c, \"systemctl restart nke-attestation\"]\n            - [sh, -c, \"systemctl restart nke-agent\"]\n            - [sh, -c, \"sysctl -p\"]\n            - [bash, -c, \"/usr/local/bin/fetch-and-install-bundle.sh https://d3mq564cn7sth7.cloudfront.net/nke_bundles/Ubuntu_24.04/aarch64/kubeadm_v1.34.2_aarch64.tgz ./kubeadm-install.py\"]\n            - [bash, -c, \"/usr/local/bin/fetch-and-install-bundle.sh https://d3mq564cn7sth7.cloudfront.net/nke_bundles/Ubuntu_24.04/aarch64/agent_v0.1.2_arm64.tgz ./agent-installer.sh\"]\n            - sed -i '/^ExecStart=/ s|\\bnke-agent\\b|nke-agent -disable-mtls -bundle-server-url https://d3mq564cn7sth7.cloudfront.net/|' /etc/systemd/system/nke-agent.service\n            - systemctl daemon-reload\n            - systemctl restart nke-agent.service\n            - [sh, -c, \"systemctl restart procps\"]\n            - [bash, -c, \"/usr/local/bin/fetch-and-install-bundle.sh https://d3mq564cn7sth7.cloudfront.net/nke_bundles/Ubuntu_24.04/aarch64/calico_v3.30.1-1_aarch64.tgz ./calico-image-import.py\"]\n"
